          timeCandidates.push({
            tag: el.tagName,
            className: (el.className || '').toString().substring(0,80),
            text: text.substring(0, 50),
            html: el.outerHTML.substring(0, 200)
          });
        }
      });

      samples.push({
        index: i,
        wrapperClasses: (w.className || '').toString().substring(0,100),
        innerHTML: w.innerHTML.substring(0, 500).replace(/</g, '<').replace(/>/g, '>'),
