    chatEls.forEach(el => {
      res.chatElements.push({
        tag: el.tagName,
        cls: (el.className || '').toString().substring(0, 120),
        childCount: el.children.length
      });
    });

    // Any list-like elements
    const lists = document.querySelectorAll('ul, ol, [class*=list]');
    res.listElements = [];
    lists.forEach(el => {
      res.listElements.push({
        tag: el.tagName,
        cls: (el.className || '').toString().substring(0, 120),
        children: el.children.length,
        firstChild: (el.children[0]?.textContent || '').trim().substring(0, 60)
      });
    });

    return JSON.stringify(res, null, 2);
  });

  console.log(result);
  await browser.close();
})().catch(e => console.error('ERR:', e.message));
