import { chromium } from 'playwright';
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  const talkFrame = page.frames()[1];

  // Click the first contact to open a conversation
  const clicked = await talkFrame.evaluate(() => {
    const container = document.querySelector('.contact-item-container');
    if (!container) return 'NO_CONTACT';
    container.click();
    const name = container.querySelector('.contact-info')?.textContent?.trim()?.substring(0, 50);
    const time = container.querySelector('.contact-time')?.textContent?.trim();
    return 'Clicked: ' + name + ' time: ' + time;
  });

  console.log('Click result:', clicked);

  // Wait for messages to load
  await new Promise(r => setTimeout(r, 3000));

  // Now explore the message DOM
  const result = await talkFrame.evaluate(() => {
    const res = {};

    // Check for message items
    const wrappers = document.querySelectorAll('.message-item-wrapper, [class*=message-item]');
    res.wrapperCount = wrappers.length;

    if (wrappers.length > 0) {
      const w = wrappers[0];
      res.firstWrapperTag = w.tagName;
      res.firstWrapperClass = (w.className || '').toString();

      // Look for time elements
      const timeEls = w.querySelectorAll('[class*=time], [class*=date], [class*=timestamp]');
