          tag: el.tagName,
          cls: (el.className || '').toString().substring(0, 80),
          text: (el.textContent || '').trim().substring(0, 30),
          outerHTML: el.outerHTML.substring(0, 150)
        });
      });

      // Get inner HTML of first wrapper
      res.firstWrapperHTML = w.innerHTML.substring(0, 500);

      // Get all class names from first wrapper
      const allCls = [];
      w.querySelectorAll('*').forEach(el => {
        const cname = (el.className || '').toString();
        if (cname) allCls.push(cname);
      });
      res.uniqueClasses = [...new Set(allCls)].filter(c => c.length > 0);
    }

    return JSON.stringify(res, null, 2);
  });

  console.log(result);
  await browser.close();
})().catch(e => console.error('ERR:', e.message));
