        innerHTML_preview: w.innerHTML.substring(0, 400),
        timeMatches,
        prevElTag: prev?.tagName || 'none',
        prevElClass: (prev?.className || '').toString().substring(0, 80),
        prevElText: (prev?.textContent || '').trim().substring(0, 30)
      });
    });

