import { chromium } from 'playwright';
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  const talkFrame = page.frames()[1];

  // Scroll chat area to load more messages
  await talkFrame.evaluate(() => {
    const scrollArea = document.querySelector('.message-scroll-wrap') ||
      document.querySelector('.message-flow-container') ||
      document.querySelector('[class*=scroll]') ||
      document.querySelector('.chat-list');
    if (scrollArea) {
      scrollArea.scrollTop = 0;
    }
  });

  await new Promise(r => setTimeout(r, 2000));

  // Now probe ALL messages for different types
  const result = await talkFrame.evaluate(() => {
    const allMsgs = [];
