      // Time
      const timeSpan = w.querySelector('.item-base-info span:last-child');
      if (timeSpan) {
        msg.time = timeSpan.textContent.trim();
      }

      // Name
      const nameSpan = w.querySelector('.item-base-info .name');
      if (nameSpan) msg.senderName = nameSpan.textContent.trim();

      // Content
      const textEl = w.querySelector('.session-rich-content.text');
      const cardEl = w.querySelector('.session-rich-content.card');
      const imgEl = w.querySelector('.session-rich-content img:not(.emotion)');
