      const emotionEls = w.querySelectorAll('img.emotion, [class*=emotion], [class*=emoji]');

      if (textEl) {
        msg.type = 'text';
        msg.content = textEl.textContent.trim().substring(0, 200);
        // Check for inline images
        const imgs = textEl.querySelectorAll('img');
        msg.inlineImages = imgs.length;
      } else if (cardEl) {
        msg.type = 'card';
        msg.content = cardEl.textContent.trim().substring(0, 200);
        msg.cardHTML = cardEl.innerHTML.substring(0, 300);
      } else {
        msg.type = 'system/other';
        msg.isSystem = !!w.querySelector('[data-exp=sysmsg]');
        msg.content = (w.textContent || '').trim().substring(0, 100);
      }

      if (imgEl && !msg.isSystem) {
        msg.hasImage = true;
        msg.imgTag = imgEl.outerHTML.substring(0, 200);
      }

      if (emotionEls.length > 0) {
        msg.emotionCount = emotionEls.length;
        msg.emotionSamples = [];
        emotionEls.forEach(e => msg.emotionSamples.push({
          tag: e.tagName,
