/**
 * 小满CRM — 图片抓取工具
 *
 * 从 TM 聊天中检测图片 URL，通过浏览器上下文下载到本地
 */
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { createHash } from 'crypto';

const __dirname = dirname(fileURLToPath(import.meta.url));
const IMAGES_DIR = join(__dirname, '..', 'images');

/**
 * 提取当前会话消息中的所有图片 URL
 */
export async function extractImageUrls(frame) {
  return frame.evaluate(() => {
    const urls = [];
    document.querySelectorAll('.message-item-wrapper.messenger img').forEach(img => {
      if (img.src && img.src.startsWith('http')) urls.push(img.src);
    });
    return [...new Set(urls)];
  });
}

/**
 * 通过浏览器上下文下载图片（复用登录态 cookie）
 * 创建临时页面 -> 导航到图片URL -> 保存响应体 -> 关闭页面
 */
async function downloadImageViaContext(ctx, url, savePath) {
  const newPage = await ctx.newPage();
  try {
    const response = await newPage.goto(url, {
      waitUntil: 'load',
      timeout: 20000,
    });
    if (!response.ok()) {
      throw new Error(`HTTP ${response.status()}`);
    }
    const buffer = await response.body();
    writeFileSync(savePath, buffer);
    return buffer.length;
  } finally {
    await newPage.close();
  }
}

/**
 * 为当前客户保存所有图片
 * @param {BrowserContext} ctx - Playwright 浏览器上下文（含登录态）
 * @param {object} frame - TM 聊天 iframe
 * @param {string} customerName - 客户名称（用于目录名）
 * @param {Set} globalDedup - 全局去重 Set（避免重复下载）
 * @returns {Promise<Array<{url: string, filePath: string, size: number}>>}
 */
export async function saveCustomerImages(ctx, frame, customerName, globalDedup) {
  const urls = await extractImageUrls(frame);
  if (urls.length === 0) return [];

  const dir = join(IMAGES_DIR, sanitizeName(customerName));
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

  const saved = [];
  for (const url of urls) {
    if (globalDedup.has(url)) continue;
    globalDedup.add(url);

    const ext = url.match(/\.(jpe?g|png|gif|webp|bmp)(?:[?#]|$)/i)?.[1] || 'jpg';
    const hash = createHash('md5').update(url).digest('hex').substring(0, 10);
    const filename = `${Date.now()}_${hash}.${ext}`;
    const filePath = join(dir, filename);

    try {
      const size = await downloadImageViaContext(ctx, url, filePath);
      saved.push({ url, filePath, size });
    } catch (err) {
      // Silent skip — some images may be expired or restricted
      console.log(`   ⚠️ 图片跳过: ${url.substring(0, 60)}… (${err.message})`);
    }
  }
  return saved;
}

/**
 * 在每条消息中检测图片并注入 URL
 */
export function extractMessageImages(frame) {
  return frame.evaluate(() => {
    const results = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      const imgs = wrapper.querySelectorAll('img');
      if (imgs.length === 0) return;
      const urls = Array.from(imgs)
        .map(img => img.src)
        .filter(s => s && s.startsWith('http'));
      if (urls.length > 0) results.push(...urls);
    });
    return [...new Set(results)];
  });
}

/**
 * 提取当前会话消息中的文件链接（云盘/下载等）
 */
export async function extractFileUrls(frame) {
  return frame.evaluate(() => {
    const files = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      // 卡消息中的链接
      wrapper.querySelectorAll('a').forEach(a => {
        const href = a.href || '';
        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
          files.push({
            url: href,
            name: (a.textContent || '').trim() || (a.title || ''),
            type: 'clouddisk',
          });
        }
      });
      // 文件类元素的文本内容
      const cardText = wrapper.querySelector('.session-rich-content.card');
      if (cardText) {
        const text = cardText.textContent || '';
        // 常见的文件格式指示
        if (/\.(pdf|docx?|xlsx?|pptx?|zip|rar|jpg|png)\b/i.test(text) && !files.some(f => f.text === text)) {
          files.push({ url: '', name: text.substring(0, 100), type: 'card_reference' });
        }
      }
    });
    return files;
  });
}

function sanitizeName(name) {
  return name.replace(/[/\\?%*:|"<>]/g, '_').substring(0, 60);
}

#!/usr/bin/env node

/**
 * 小满CRM — TM + 邮件数据整合 v2
 *
 * 过滤系统邮件 → 按客户名合并 → 生成客户档案
 *
 * 用法: node integrate.mjs
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');

// ============================================================
// 系统邮件黑名单
// ============================================================
const SYSTEM_SENDERS = [
  'feedback@service.alibaba.com',
  'feedback@email.alibaba.com',
  'alisourcepro@service.alibaba.com',
  'noreply@github.com',
  'notification@alibaba.com',
  'no-reply@alibaba.com',
];

const SYSTEM_SUBJECT_PATTERNS = [
  'Alibaba Inquiry Notification',
  '银牌RFQ',
  'You received new messages',
  'GitHub Copilot',
  'Trade Center',
];

function isSystemEmail(email) {
  const sender = (email.senderEmail || '').toLowerCase();
  if (SYSTEM_SENDERS.some(s => sender.includes(s))) return true;
  const subject = (email.subject || '');
  if (SYSTEM_SUBJECT_PATTERNS.some(p => subject.includes(p))) return true;
  return false;
}

// ============================================================
// 加载数据
// ============================================================
function loadLatest(pattern) {
  const files = readdirSync(DATA_DIR)
    .filter(f => f.startsWith(pattern) && f.endsWith('.json'))
    .sort().reverse();
  if (!files.length) return [];
  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf-8'));
}

// ============================================================
// 匹配客户名
// ============================================================
function matchCustomer(text, names) {
  if (!text) return null;
  const lower = text.toLowerCase();
  for (const name of names) {
    if (!name || name === 'User name') continue;
    if (lower.includes(name.toLowerCase())) return name;
    const parts = name.toLowerCase().split(/\s+/).filter(Boolean);
    for (const part of parts) {
      if (part.length > 2 && lower.includes(part)) return name;
    }
  }
  return null;
}

// ============================================================
// 主流程
// ============================================================
function main() {
  console.log('╔══════════════════════════════════════╗');
  console.log('║   小满CRM 数据整合 v2                ║');
  console.log('║   TM + 邮件(已过滤系统邮件)           ║');
  console.log('╚══════════════════════════════════════╝\n');

  const tmData = loadLatest('数据_');
  const rawMail = loadLatest('邮件数据_');
  const sentData = loadLatest('发件数据_');

  // 过滤系统邮件
  const systemEmails = rawMail.filter(isSystemEmail);
  const realEmails = rawMail.filter(e => !isSystemEmail(e));

  // 发件全部是真实业务邮件，保留
  const realSent = [...sentData];

  console.log(`📂 加载数据:`);
  console.log(`   TM 聊天: ${tmData.length} 个会话`);
  console.log(`   收件原始: ${rawMail.length} 封`);
  console.log(`   🗑️ 过滤系统邮件: ${systemEmails.length} 封`);
  console.log(`   ✅ 真实收件: ${realEmails.length} 封`);
  console.log(`   ✅ 真实发件: ${realSent.length} 封\n`);

  const customerNames = [...new Set(tmData.map(c => c.name).filter(Boolean))];
  console.log(`👥 TM 客户: ${customerNames.length} 个`);

  // 为每个客户建立档案
  const archives = customerNames.map(name => {
    const tm = tmData.find(c => c.name === name);
    const tmMessages = tm?.messages || [];
    const tmImages = tm?.images || [];
    const classification = tm?.classification || null;

    // 匹配真实收件
    const inboxMails = realEmails.filter(m => m.customerName === name);
    // 匹配发件
    const sentMails = realSent.filter(m => {
      if (matchCustomer(m.senderName || m.senderEmail, [name])) return true;
      if (matchCustomer(m.subject || '', [name])) return true;
      return false;
    });

    // 额外：从发件箱收件人找新客户（不在 TM 中的）
    const totalEmails = inboxMails.length + sentMails.length;

    return {
      name,
      classification,
      tm: {
        messageCount: tmMessages.length,
        messages: tmMessages,
        images: tmImages,
      },
      emails: {
        total: totalEmails,
        inbox: inboxMails.map(m => ({
          subject: m.subject, time: m.time,
          body: m.bodyText?.substring(0, 3000) || '',
          images: m.images || [],
        })),
        sent: sentMails.map(m => ({
          to: m.senderName || m.senderEmail,
          subject: m.subject, time: m.time,
          body: m.bodyText?.substring(0, 3000) || '',
          images: m.images || [],
        })),
      },
    };
  });

  // 找出发件中匹配不到任何 TM 客户的独立业务联系人
  const matchedSentRecipients = new Set();
  for (const a of archives) {
    for (const m of a.emails.sent) {
      matchedSentRecipients.add(m.to);
    }
  }
  const otherContacts = realSent
    .filter(m => !matchedSentRecipients.has(m.senderName || m.senderEmail))
    .map(m => ({
      name: m.senderName || m.senderEmail,
      subject: m.subject, time: m.time,
      body: m.bodyText?.substring(0, 3000) || '',
      images: m.images || [],
    }));

  // 去重
  const uniqueOthers = [];
  const seen = new Set();
  for (const c of otherContacts) {
    if (!seen.has(c.name)) {
      seen.add(c.name);
      uniqueOthers.push(c);
    }
  }

  // 统计
  const totalTmMsg = archives.reduce((s, a) => s + a.tm.messageCount, 0);
  const totalTmImg = archives.reduce((s, a) => s + a.tm.images.length, 0);
  const totalEmail = archives.reduce((s, a) => s + a.emails.total, 0);
  const totalEmailImg = archives.reduce((s, a) => {
    const inboxImgs = a.emails.inbox.reduce((ss, m) => ss + m.images.length, 0);
    const sentImgs = a.emails.sent.reduce((ss, m) => ss + m.images.length, 0);
    return s + inboxImgs + sentImgs;
  }, 0);

  // 保存
  const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
  const mergedPath = join(DATA_DIR, `客户档案_${timestamp}.json`);
  const summary = {
    generatedAt: timestamp,
    stats: {
      totalCustomers: archives.length,
      totalTmMessages: totalTmMsg,
      totalTmImages: totalTmImg,
      totalEmails: totalEmail,
      totalEmailImages: totalEmailImg,
      filteredSystemEmails: systemEmails.length,
      otherBusinessContacts: uniqueOthers.length,
    },
    otherContacts: uniqueOthers,
    customers: archives,
  };
  writeFileSync(mergedPath, JSON.stringify(summary, null, 2), 'utf-8');

  // 输出
  console.log(`\n📊 整合结果`);
  console.log(`   ${'─'.repeat(40)}`);
  console.log(`   客户: ${archives.length} 个`);
  console.log(`   TM 消息: ${totalTmMsg} 条`);
  console.log(`   TM 图片: ${totalTmImg} 张`);
  console.log(`   关联邮件: ${totalEmail} 封`);
  console.log(`   邮件图片: ${totalEmailImg} 张`);
  console.log(`   过滤系统邮件: ${systemEmails.length} 封`);
  console.log(`   其他业务联系人(发件): ${uniqueOthers.length} 个\n`);

  console.log('📋 客户档案清单：');
  console.log(`   ${'─'.repeat(60)}`);
  for (const a of archives) {
    const n = a.name.padEnd(30);
    const tm = `${a.tm.messageCount}条/${a.tm.images.length}图`.padEnd(15);
    const em = `${a.emails.total}封`;
    const cat = a.classification ? (a.classification.categoryId || '') : '';
    console.log(`   ${n} TM:${tm} 邮件:${em}  [${cat}]`);
  }

  if (uniqueOthers.length > 0) {
    console.log(`\n📋 其他业务联系人（仅有邮件往来）：`);
    for (const c of uniqueOthers) {
      console.log(`   ${c.name} — ${c.subject.substring(0, 50)}`);
    }
  }

  console.log(`\n   已保存: ${mergedPath}`);
  return summary;
}

main();

/**
 * 小满CRM — 图片抓取工具
 *
 * 从 TM 聊天中检测图片 URL，通过浏览器上下文下载到本地
 */
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { createHash } from 'crypto';

const __dirname = dirname(fileURLToPath(import.meta.url));
const IMAGES_DIR = join(__dirname, '..', 'images');

/**
 * 提取当前会话消息中的所有图片 URL
 */
export async function extractImageUrls(frame) {
  return frame.evaluate(() => {
    const urls = [];
    document.querySelectorAll('.message-item-wrapper.messenger img').forEach(img => {
      if (img.src && img.src.startsWith('http')) urls.push(img.src);
    });
    return [...new Set(urls)];
  });
}

/**
 * 通过浏览器上下文下载图片（复用登录态 cookie）
 * 创建临时页面 -> 导航到图片URL -> 保存响应体 -> 关闭页面
 */
async function downloadImageViaContext(ctx, url, savePath) {
  const newPage = await ctx.newPage();
  try {
    const response = await newPage.goto(url, {
      waitUntil: 'load',
      timeout: 20000,
    });
    if (!response.ok()) {
      throw new Error(`HTTP ${response.status()}`);
    }
    const buffer = await response.body();
    writeFileSync(savePath, buffer);
    return buffer.length;
  } finally {
    await newPage.close();
  }
}

/**
 * 为当前客户保存所有图片
 * @param {BrowserContext} ctx - Playwright 浏览器上下文（含登录态）
 * @param {object} frame - TM 聊天 iframe
 * @param {string} customerName - 客户名称（用于目录名）
 * @param {Set} globalDedup - 全局去重 Set（避免重复下载）
 * @returns {Promise<Array<{url: string, filePath: string, size: number}>>}
 */
export async function saveCustomerImages(ctx, frame, customerName, globalDedup) {
  const urls = await extractImageUrls(frame);
  if (urls.length === 0) return [];

  const dir = join(IMAGES_DIR, sanitizeName(customerName));
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

  const saved = [];
  for (const url of urls) {
    if (globalDedup.has(url)) continue;
    globalDedup.add(url);

    const ext = url.match(/\.(jpe?g|png|gif|webp|bmp)(?:[?#]|$)/i)?.[1] || 'jpg';
    const hash = createHash('md5').update(url).digest('hex').substring(0, 10);
    const filename = `${Date.now()}_${hash}.${ext}`;
    const filePath = join(dir, filename);

    try {
      const size = await downloadImageViaContext(ctx, url, filePath);
      saved.push({ url, filePath, size });
    } catch (err) {
      // Silent skip — some images may be expired or restricted
      console.log(`   ⚠️ 图片跳过: ${url.substring(0, 60)}… (${err.message})`);
    }
  }
  return saved;
}

/**
 * 在每条消息中检测图片并注入 URL
 */
export function extractMessageImages(frame) {
  return frame.evaluate(() => {
    const results = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      const imgs = wrapper.querySelectorAll('img');
      if (imgs.length === 0) return;
      const urls = Array.from(imgs)
        .map(img => img.src)
        .filter(s => s && s.startsWith('http'));
      if (urls.length > 0) results.push(...urls);
    });
    return [...new Set(results)];
  });
}

/**
 * 提取当前会话消息中的文件链接（云盘/下载等）
 */
export async function extractFileUrls(frame) {
  return frame.evaluate(() => {
    const files = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
      // 卡消息中的链接
      wrapper.querySelectorAll('a').forEach(a => {
        const href = a.href || '';
        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
          files.push({
            url: href,
            name: (a.textContent || '').trim() || (a.title || ''),
            type: 'clouddisk',
          });
        }
      });
      // 文件类元素的文本内容
      const cardText = wrapper.querySelector('.session-rich-content.card');
      if (cardText) {
        const text = cardText.textContent || '';
        // 常见的文件格式指示
        if (/\.(pdf|docx?|xlsx?|pptx?|zip|rar|jpg|png)\b/i.test(text) && !files.some(f => f.text === text)) {
          files.push({ url: '', name: text.substring(0, 100), type: 'card_reference' });
        }
      }
    });
    return files;
  });
}

function sanitizeName(name) {
  return name.replace(/[/\\?%*:|"<>]/g, '_').substring(0, 60);
}

/**
 * 小满CRM — 聊天记录抓取器 v2
 *
 * 用法: node scraper.mjs
 * 前置条件: Chrome 端口9222已开启，小满已登录并在TM消息页
 */

import { chromium } from 'playwright';
import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { saveCustomerImages } from './image-utils.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const CDP_URL = 'http://127.0.0.1:9222';

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, ctx, page, talkFrame };
}

/**
 * 提取会话列表
 */
async function getConversationList(frame) {
  return frame.evaluate(() => {
    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
      const text = el.textContent || '';
      // Extract name from .contact-right (avoids avatar initial prefix issue)
      const nameEl = el.querySelector('.contact-right');
      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';

      const isSelected = el.classList.contains('selected');
      const isUnread = text.includes('[未读]');
      const lastMsg = nameText.replace(/^.+?\d{2,4}[-:\/]\d{1,2}[-:\/]?\d{0,2}\s*/, '').replace(/\[(未读|已读)\]\s*/, '').trim();

      return { name, isUnread, isSelected, lastMessage: lastMsg.substring(0, 200) };
    });
  });
}

/**
 * 滚动会话列表到底部以确保所有项都在DOM中
 */
async function scrollConversationList(frame) {
  await frame.evaluate(() => {
    const container = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content') ||
      document.querySelector('.im-conversation-list-container');
    if (container) {
      container.scrollTop = container.scrollHeight;
    }
  });
  await new Promise(r => setTimeout(r, 500));
}

/**
 * 获取当前会话的完整消息
 */
async function getCurrentMessages(frame) {
  return frame.evaluate(() => {
    const messages = [];
    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');

    wrappers.forEach(wrapper => {
      const isLeft = wrapper.classList.contains('item-left');
      const isRight = wrapper.classList.contains('item-right');

      const textEl = wrapper.querySelector('.session-rich-content.text');
      const cardEl = wrapper.querySelector('.session-rich-content.card');
      const securityEl = wrapper.querySelector('.session-security');
      const avatarEl = wrapper.querySelector('.session-avatar.head-portrait.messenger');
      const autoReply = wrapper.querySelector('.session-rich-content')?.textContent || '';

      if (!textEl && !cardEl && !securityEl) return;

      // Skip system messages
      if (securityEl) return;

      const content = (textEl || cardEl).textContent.trim();
      const avatar = avatarEl ? (avatarEl.textContent || '').trim() : '';

      // Clean up content - remove translation artifacts
      const cleanContent = content
        .replace(/翻译中…反馈$/, '')
        .replace(/由阿里翻译提供反馈$/, '')
        .replace(/阿里国际Marco大模型翻译反馈$/, '')
        .replace(/由阿里翻译提供$/, '')
        .trim();

      messages.push({
        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
        content: cleanContent,
        isCard: !!cardEl,
        sender: avatar || undefined,
        isAutoReply: autoReply.includes('自动接待发送') || autoReply.includes('去优化'),
      });
    });

    return messages;
  });
}

/**
 * 点击指定索引的联系人
 */
async function clickConversation(frame, index) {
  const result = await frame.evaluate((idx) => {
    const containers = document.querySelectorAll('.contact-item-container');
    const target = containers[idx];
    if (!target) return null;
    target.scrollIntoView({ block: 'center' });
    target.click();
    return (target.textContent || '').trim().substring(0, 150);
  }, index);
  await new Promise(r => setTimeout(r, 2000));
  return result;
}

/**
 * 等待并确认消息区域已更新（非空白）
 */
async function waitForMessages(frame) {
  for (let i = 0; i < 10; i++) {
    const hasContent = await frame.evaluate(() => {
      const msgs = document.querySelectorAll('.session-rich-content.text, .session-rich-content.card');
      return msgs.length > 0;
    });
    if (hasContent) return true;
    await new Promise(r => setTimeout(r, 500));
  }
  return false;
}

async function scrapeAll() {
  console.log('=== 小满CRM聊天记录抓取 v2 ===\n');
  const { browser, ctx, talkFrame } = await connect();
  console.log('✅ 已连接到小满');

  try {
    // 1. 获取完整会话列表
    console.log('\n📋 获取会话列表...');
    // Scroll to ensure all items rendered
    await scrollConversationList(talkFrame);
    await scrollConversationList(talkFrame);
    const conversations = await getConversationList(talkFrame);
    console.log(`   共 ${conversations.length} 个会话`);

    conversations.forEach((c, i) => {
      const status = c.isSelected ? '🟢' : c.isUnread ? '📩' : '  ';
      console.log(`  ${status} [${i}] ${c.name}`);
    });

    // 2. 切换各筛选Tab，统计
    console.log('\n📊 筛选统计...');
    const filterLabels = ['全部', '未读', '待回复', '待跟进'];
    const filterCounts = {};

    for (const label of filterLabels) {
      await frameEvaluateClickTab(talkFrame, label);
      const list = await getConversationList(talkFrame);
      filterCounts[label] = list.length;
      console.log(`   ${label}: ${list.length} 个会话`);
    }

    // 回到"全部"
    await frameEvaluateClickTab(talkFrame, '全部');
    await new Promise(r => setTimeout(r, 1000));

    // 3. 遍历所有会话获取详情（限前25个，避免太慢）
    const allData = [];
    const total = Math.min(conversations.length, 25);
    const imageDedup = new Set(); // 全局图片去重

    for (let i = 0; i < total; i++) {
      const conv = conversations[i];
      if (conv.name === 'Assistant Eva官方') continue; // Skip system account

      process.stdout.write(`\r💬 [${i + 1}/${total}] ${conv.name}...`);

      const clicked = await clickConversation(talkFrame, i);
      if (!clicked) {
        console.log(`\n   ⚠️ 无法点击索引 ${i}`);
        continue;
      }

      await waitForMessages(talkFrame);
      const messages = await getCurrentMessages(talkFrame);

      // 提取并保存该客户的图片
      const savedImages = await saveCustomerImages(ctx, talkFrame, conv.name, imageDedup);
      if (savedImages.length > 0) {
        process.stdout.write(`📷${savedImages.length} `);
      }

      // Re-get conv data to get current status
      const updatedList = await getConversationList(talkFrame);
      const current = updatedList[i] || conv;

      allData.push({
        name: current.name,
        status: current.isUnread ? 'unread' : 'read',
        lastMessageSnippet: current.lastMessage,
        messageCount: messages.length,
        messages: messages.slice(-50), // Last 50 messages max
        images: savedImages.length > 0 ? savedImages : undefined,
      });
    }

    console.log('\n');

    // 4. 保存
    const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
    const outputPath = join(DATA_DIR, `数据快照_${timestamp}.json`);
    writeFileSync(outputPath, JSON.stringify(allData, null, 2), 'utf-8');

    // 5. 生成摘要
    const totalMsg = allData.reduce((sum, c) => sum + c.messages.length, 0);
    const totalImg = allData.reduce((sum, c) => sum + (c.images?.length || 0), 0);
    const unreadCount = allData.filter(c => c.status === 'unread').length;
    console.log(`\n✅ 抓取完成`);
    console.log(`   会话: ${allData.length} | 总消息: ${totalMsg} | 图片: ${totalImg} | 未读: ${unreadCount}`);
    console.log(`   已保存: ${outputPath}`);

    return allData;
  } finally {
    await browser.close();
  }
}

async function frameEvaluateClickTab(frame, label) {
  return frame.evaluate((tabLabel) => {
    const tabs = document.querySelectorAll('.im-next-tabs-tab.list-tab-item');
    for (const tab of tabs) {
      if ((tab.textContent || '').trim() === tabLabel) {
        tab.click();
        return true;
      }
    }
    return false;
  }, label);
}

scrapeAll().catch(err => {
  console.error('\n❌ 抓取失败:', err.message);
  process.exit(1);
});

/**
 * 小满CRM — 会话分类引擎
 *
 * 将每个会话归类到 11 个类别之一，并分配 S/A/B/C 优先级。
 *
 * 使用方式：
 *   import { classifyConversation } from './classifier.mjs';
 *   const result = classifyConversation(conversation);
 */

// ============================================================
// 分类定义
// ============================================================

export const CATEGORIES = [
  { id: 'awaiting_reply',    label: '待回复',   emoji: '🔴', priority: 'P0', desc: '客户发来消息，我方未回复' },
  { id: 'awaiting_quote',    label: '待报价',   emoji: '🟠', priority: 'P0', desc: '客户询盘，未正式报价' },
  { id: 'negotiating',       label: '谈判中',   emoji: '💬', priority: 'P0', desc: '正讨论价格/条款/细节' },
  { id: 'after_sales',       label: '售后处理', emoji: '⚠️', priority: 'P0', desc: '质量投诉、退换货' },
  { id: 'sample_request',    label: '待寄样',   emoji: '📦', priority: 'P1', desc: '客户要求样品' },
  { id: 'sample_followup',   label: '样品跟进', emoji: '🔬', priority: 'P1', desc: '样品已寄出，等反馈' },
  { id: 'awaiting_payment',  label: '待付款',   emoji: '🟡', priority: 'P1', desc: 'PI已发，等付款' },
  { id: 'awaiting_delivery', label: '待发货',   emoji: '🟢', priority: 'P1', desc: '已收款，未发货' },
  { id: 'followup',          label: '待回访',   emoji: '🔵', priority: 'P2', desc: '历史有交互，超N天未联系' },
  { id: 'keep_warm',         label: '保持粘性', emoji: '🟣', priority: 'P3', desc: '老客户/长期客户维系' },
  { id: 'activate',          label: '待激活',   emoji: '⚪', priority: 'P3', desc: '新线索/低互动客户' },
];

// ============================================================
// 关键词定义
// ============================================================

const KEYWORDS = {
  // 价格/报价相关
  price: ['price', 'quote', 'quotation', 'cost', 'how much', '收费', '价格', '报价', 'money', 'dollar', 'usd', 'pi', 'proforma', 'invoice'],
  // 样品相关
  sample: ['sample', '样品', '试样', 'test order', 'try', 'trial', 'small order', 'sample fee'],
  // 付款相关
  payment: ['payment', 'pay', 'deposit', '定金', '预付', '付款', 'tt', 'wire transfer', 'bank', '账期'],
  // 售后相关
  after_sales: ['complaint', 'return', 'refund', '退换', '退款', '投诉', 'quality', 'damage', 'wrong', 'defect', '破损', 'quality issue', 'not as described'],
  // 物流相关
  shipping: ['ship', 'delivery', 'logistics', '海运', '空运', '快递', 'dhl', 'fedex', 'ups', '海运', 'shipping cost', 'freight'],
  // 谈判相关
  negotiation: ['negotiate', 'discount', 'better price', 'cheaper', '最低', '优惠', '折扣', 'moq', 'minimum', '交期', 'lead time'],
  // 合作意向
  interest: ['interested', '合作', 'order', 'purchase', 'buy', '采购', '下单', 'confirm', '确认订单', 'catalog', 'product list'],
  // 客户信息询问
  inquiry: ['what is', 'tell me', 'do you have', '可以提供', '能做', '定制', 'custom', 'odm', 'oem', 'printing'],
  // 跟进问候
  followup_greeting: ['how are you', 'checking in', 'following up', 'just follow', 'any thought', 'any update', 'how is everything'],
};

// ============================================================
// 辅助函数
// ============================================================

function lastMessage(messages) {
  return messages.length > 0 ? messages[messages.length - 1] : null;
}

function firstMessage(messages) {
  return messages.length > 0 ? messages[0] : null;
}

function hasKeywords(text, keywordList) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return keywordList.some(kw => lower.includes(kw.toLowerCase()));
}

function extractSentMessages(messages) {
  return messages.filter(m => m.side === 'sent');
}

function extractReceivedMessages(messages) {
  return messages.filter(m => m.side === 'received');
}

function countKeywordMatches(text, keywordList) {
  if (!text) return 0;
  const lower = text.toLowerCase();
  return keywordList.filter(kw => lower.includes(kw.toLowerCase())).length;
}

/**
 * 估算消息时间戳（相对当前时间）
 */
function estimateHoursAgo(messageIndex, totalMessages, avgHoursPerMsg = 4) {
  // Rough estimate: each message back and forth is about 4 hours apart
  // This is very approximate
  return (totalMessages - messageIndex) * avgHoursPerMsg;
}

// ============================================================
// 分类引擎
// ============================================================

/**
 * @param {Object} conv - 会话对象 { name, status, messages: [{ side, content, isCard }] }
 * @returns {{ categoryId: string, tier: string, confidence: number, reasons: string[] }}
 */
export function classifyConversation(conv) {
  const { messages = [], status } = conv;
  const last = lastMessage(messages);
  const first = firstMessage(messages);
  const sent = extractSentMessages(messages);
  const received = extractReceivedMessages(messages);
  const reasons = [];

  if (messages.length === 0) {
    return { categoryId: 'activate', tier: 'C', confidence: 0.5, reasons: ['无消息记录'] };
  }

  const lastContent = last ? last.content.toLowerCase() : '';
  const allContent = messages.map(m => m.content).join(' ').toLowerCase();
  const sentContent = sent.map(m => m.content).join(' ').toLowerCase();
  const receivedContent = received.map(m => m.content).join(' ').toLowerCase();

  // ===================================================
  // 规则引擎（按优先级）
  // ===================================================

  // 规则 1: 售后处理 — 投诉/退换货关键词
  if (hasKeywords(allContent, KEYWORDS.after_sales)) {
    const matchCount = countKeywordMatches(allContent, KEYWORDS.after_sales);
    if (matchCount >= 1) {
      reasons.push(`含售后关键词(${matchCount}次)`);
      const tier = matchCount >= 3 ? 'S' : 'A';
      return { categoryId: 'after_sales', tier, confidence: 0.8, reasons };
    }
  }

  // 规则 2: 待回复 — 最后一条消息是客户发的，我方未回复
  if (last && last.side === 'received') {
    const lastSent = sent.length > 0 ? sent[sent.length - 1] : null;
    const lastReceived = received[received.length - 1];
    if (!lastSent || messages.indexOf(lastReceived) > messages.indexOf(lastSent)) {
      reasons.push('客户最后发言，我方未回复');
      // Check if it's a price inquiry or just a simple message
      const isQuoteRequest = hasKeywords(lastContent, KEYWORDS.price) || hasKeywords(lastContent, KEYWORDS.inquiry);
      const isSimpleReply = lastContent.length < 30 && !hasKeywords(lastContent, [...KEYWORDS.price, ...KEYWORDS.interest]);

      if (isQuoteRequest) {
        reasons.push('包含询价/询盘内容');
        return { categoryId: 'awaiting_quote', tier: 'A', confidence: 0.85, reasons };
      }
      if (hasKeywords(lastContent, KEYWORDS.payment)) {
        reasons.push('客户询问付款');
        return { categoryId: 'awaiting_payment', tier: 'S', confidence: 0.8, reasons };
      }
      if (hasKeywords(lastContent, KEYWORDS.sample)) {
        reasons.push('客户提及样品');
        return { categoryId: 'sample_request', tier: 'A', confidence: 0.75, reasons };
      }
      if (isSimpleReply) {
        reasons.push('简短回复，可能是确认或跟进');
        // Is this after we sent a quote/PI?
        const recentSentContent = sent.slice(-3).map(m => m.content).join(' ').toLowerCase();
        if (hasKeywords(recentSentContent, [...KEYWORDS.price, ...KEYWORDS.payment])) {
          reasons.push('我方最近发送过报价');
          return { categoryId: 'awaiting_reply', tier: 'A', confidence: 0.75, reasons };
        }
      }
      return { categoryId: 'awaiting_reply', tier: 'B', confidence: 0.7, reasons };
    }
  }

  // 规则 3: 谈判中 — 双方有互动，讨论价格/条款
  if (sent.length >= 2 && received.length >= 2) {
    const hasPrice = hasKeywords(allContent, KEYWORDS.price);
    const hasNegotiation = hasKeywords(allContent, KEYWORDS.negotiation);
    if (hasPrice || hasNegotiation) {
      reasons.push('双方多轮互动');
      if (hasPrice) reasons.push('讨论价格');
      if (hasNegotiation) reasons.push('涉及谈判');
      const tier = hasPrice && hasNegotiation ? 'S' : (hasPrice ? 'A' : 'B');
      return { categoryId: 'negotiating', tier, confidence: 0.8, reasons };
    }
  }

  // 规则 4: 待付款 — 我方发送了报价/PI，等待客户付款
  if (hasKeywords(sentContent, KEYWORDS.payment) || hasKeywords(sentContent, KEYWORDS.price)) {
    // Last message was from us about payment/price, customer hasn't responded or responded briefly
    if (last && last.side === 'sent') {
      const hasPaymentKeywords = hasKeywords(lastContent, KEYWORDS.payment) || hasKeywords(sentContent, KEYWORDS.payment);
      if (hasPaymentKeywords) {
        reasons.push('我方发送了付款相关信息');
        return { categoryId: 'awaiting_payment', tier: 'A', confidence: 0.7, reasons };
      }
      if (hasKeywords(sentContent, KEYWORDS.price)) {
        reasons.push('我方已发送报价');
        // Check if customer replied
        const recentCustomerMessages = received.slice(-2);
        const hasCustomerInterest = recentCustomerMessages.some(m =>
          hasKeywords(m.content, [...KEYWORDS.interest, ...KEYWORDS.negotiation])
        );
        if (hasCustomerInterest) {
          return { categoryId: 'negotiating', tier: 'A', confidence: 0.75, reasons };
        }
        return { categoryId: 'awaiting_quote', tier: 'B', confidence: 0.65, reasons };
      }
    }
  }

  // 规则 5: 样品相关
  if (hasKeywords(allContent, KEYWORDS.sample)) {
    reasons.push('涉及样品讨论');
    if (last && last.side === 'received') {
      // Customer's last message was about samples
      return { categoryId: 'sample_followup', tier: 'A', confidence: 0.7, reasons };
    }
    // We last spoke about samples
    const sampleSent = sent.some(m => hasKeywords(m.content, KEYWORDS.sample));
    if (sampleSent && last && last.side === 'sent') {
      return { categoryId: 'sample_followup', tier: 'B', confidence: 0.65, reasons };
    }
    return { categoryId: 'sample_request', tier: 'B', confidence: 0.6, reasons };
  }

  // 规则 6: 消息量判断
  const totalMsgCount = messages.length;

  // 只有1-2条消息 = 新线索/待激活
  if (totalMsgCount <= 2) {
    reasons.push(`仅有${totalMsgCount}条消息`);
    return { categoryId: 'activate', tier: 'C', confidence: 0.7, reasons };
  }

  // 3-5条消息 = 可能是潜在客户待跟进
  if (totalMsgCount <= 5) {
    if (last && last.side === 'sent') {
      reasons.push('少量互动，我方最后发言');
      return { categoryId: 'followup', tier: 'B', confidence: 0.6, reasons };
    }
    reasons.push('少量互动');
    return { categoryId: 'activate', tier: 'C', confidence: 0.55, reasons };
  }

  // 规则 7: 我方最后发言但客户未回复 → 待回访
  if (last && last.side === 'sent') {
    reasons.push('我方最后发言');
    const recentContent = messages.slice(-3).map(m => m.content).join(' ').toLowerCase();

    if (hasKeywords(recentContent, [...KEYWORDS.followup_greeting, ...KEYWORDS.inquiry])) {
      reasons.push('含跟进/问候内容');
      return { categoryId: 'followup', tier: 'B', confidence: 0.7, reasons };
    }
    return { categoryId: 'followup', tier: 'C', confidence: 0.55, reasons };
  }

  // 规则 8: 默认
  if (totalMsgCount > 10) {
    reasons.push('历史互动较多');
    return { categoryId: 'keep_warm', tier: 'C', confidence: 0.4, reasons };
  }

  return { categoryId: 'activate', tier: 'C', confidence: 0.3, reasons };
}

/**
 * 批量分类
 */
export function classifyAll(conversations) {
  return conversations.map(conv => ({
    ...conv,
    classification: classifyConversation(conv),
  }));
}

/**
 * 获取分类详情
 */
export function getCategoryInfo(categoryId) {
  return CATEGORIES.find(c => c.id === categoryId);
}

/**
 * 按分类统计
 */
export function categorizeSummary(classifiedConversations) {
  const summary = {};
  for (const cat of CATEGORIES) {
    summary[cat.id] = { ...cat, conversations: [], count: 0 };
  }

  // 未匹配的归入其他
  summary.other = { id: 'other', label: '其他', emoji: '❓', priority: 'P4', conversations: [], count: 0 };

  for (const conv of classifiedConversations) {
    const catId = conv.classification?.categoryId || 'other';
    if (summary[catId]) {
      summary[catId].conversations.push(conv);
      summary[catId].count++;
    } else {
      summary.other.conversations.push(conv);
      summary.other.count++;
    }
  }

  // 按优先级排序
  const priority = { 'P0': 0, 'P1': 1, 'P2': 2, 'P3': 3, 'P4': 4 };
  return Object.values(summary)
    .filter(c => c.count > 0)
    .sort((a, b) => (priority[a.priority] || 99) - (priority[b.priority] || 99));
}

