    console.log(`\n=== IMAGES (${imageEntries.length}) ===`);
    imageEntries.forEach(img => console.log(`  msg[${img.messageIndex}]: ${img.url}`));
  } else {
    console.log('\n(No images found)');
  }

  // Check for card data
  const cards = messages.filter(m => m.messageType === 'card');
  if (cards.length > 0) {
    console.log(`\n=== CARD MESSAGES (${cards.length}) ===`);
