#!/usr/bin/env node
/**
 * Targeted Amerly test scrape — validate new scraper features
 */
import { chromium } from 'playwright';

const CDP_URL = 'http://127.0.0.1:9222';

async function testAmerly() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman') || p.url().includes('crm.xiaoman'));
  const talkFrame = page.frames()[1];

  // Click amer ly (index 1)
  console.log('Clicking "amer ly"...');
  const clicked = await talkFrame.evaluate((idx) => {
    const containers = document.querySelectorAll('.contact-item-container');
    const target = containers[idx];
    if (!target) return null;
    target.scrollIntoView({ block: 'center' });
    target.click();
    return (target.textContent || '').trim().substring(0, 100);
  }, 1);
  console.log('Clicked:', clicked);
  await new Promise(r => setTimeout(r, 2000));

  // Wait for messages
  let hasContent = false;
  for (let i = 0; i < 10; i++) {
    hasContent = await talkFrame.evaluate(() => {
      const msgs = document.querySelectorAll('.session-rich-content.text, .session-rich-content.card');
      return msgs.length > 0;
    });
    if (hasContent) break;
    await new Promise(r => setTimeout(r, 500));
  }
  console.log('Messages loaded:', hasContent);

  // Scroll to load ALL messages (virtual scroll)
  console.log('\nScrolling chat to load history...');
  let prevCount = 0;
  let stableCount = 0;
  for (let i = 0; i < 60; i++) {
    const result = await talkFrame.evaluate(() => {
      let container = document.querySelector('.message-list-container') ||
        document.querySelector('.chat-list') || document.querySelector('.im-chat-list') ||
        document.querySelector('[class*="message-list"]') || document.querySelector('[class*="chat-list"]');
      if (!container) {
        const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
        if (wrappers.length > 0) {
          let el = wrappers[0].parentElement;
          while (el) {
            if (el.scrollHeight > el.clientHeight) { container = el; break; }
            el = el.parentElement;
          }
        }
      }
      if (!container) return { count: 0, scrolled: false };
      const oldScrollTop = container.scrollTop;
      container.scrollTop = 0;
      return {
        count: document.querySelectorAll('.message-item-wrapper.messenger').length,
        scrolled: oldScrollTop > 0,
      };
    });
    if (result.scrolled) await new Promise(r => setTimeout(r, 800));
    const newCount = await talkFrame.evaluate(() =>
      document.querySelectorAll('.message-item-wrapper.messenger').length
    );
    if (newCount === prevCount) {
      stableCount++;
      if (stableCount >= 3) break;
    } else {
      stableCount = 0;
      console.log(`  ${prevCount} → ${newCount} messages`);
    }
    prevCount = newCount;
    if (!result.scrolled) break;
  }
  console.log(`Total messages loaded: ${prevCount}\n`);

  // Get rendered messages with full detail
  const messages = await talkFrame.evaluate(() => {
    const msgs = [];
    document.querySelectorAll('.message-item-wrapper.messenger').forEach((wrapper, index) => {
      const isLeft = wrapper.classList.contains('item-left');
      const isRight = wrapper.classList.contains('item-right');
      const isSystem = wrapper.hasAttribute('data-exp') && wrapper.getAttribute('data-exp') === 'sysmsg';

      const textEl = wrapper.querySelector('.session-rich-content.text');
      const cardEl = wrapper.querySelector('.session-rich-content.card');
      const securityEl = wrapper.querySelector('.session-security');
      if (securityEl) return;

      let messageType = 'text';
      if (isSystem) messageType = 'system';
      else if (cardEl) messageType = 'card';

      const contentEl = textEl || cardEl;
      let content = contentEl ? contentEl.textContent.trim() : '';
      content = content
        .replace(/翻译中…反馈$/, '')
        .replace(/由阿里翻译提供反馈$/, '')
        .replace(/阿里国际Marco大模型翻译反馈$/, '')
        .replace(/由阿里翻译提供$/, '')
        .trim();

      const timeEl = wrapper.querySelector('p.item-base-info span:last-child');
      const timestamp = timeEl ? (timeEl.textContent || '').trim() : null;

      const nameEl = wrapper.querySelector('p.item-base-info span.name');
      const sender = nameEl ? (nameEl.textContent || '').trim() : '';

      const emotionEls = wrapper.querySelectorAll('img.emotion');
      const emojis = Array.from(emotionEls).map(img => img.alt || img.src || '').filter(Boolean);

      msgs.push({
        index,
        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
        content: content.substring(0, 300),
        messageType,
        timestamp,
        sender,
        emojis: emojis.length > 0 ? emojis : undefined,
      });
    });
    return msgs;
  });

  console.log('=== AMERLY MESSAGES ===');
  console.log(`Total: ${messages.length} messages\n`);
  messages.forEach(m => {
    const ts = (m.timestamp || '(no ts)').padEnd(19);
    const type = m.messageType.padEnd(6);
    const side = m.side.padEnd(8);
    const emoji = m.emojis ? ' [' + m.emojis.join(' ') + ']' : '';
    console.log(`[${String(m.index).padStart(2)}] ${ts} | ${side} | ${type} | ${m.content.substring(0, 100)}${emoji}`);
  });

  // Check for images
  const imageEntries = await talkFrame.evaluate(() => {
    const results = [];
    const seen = new Set();
    document.querySelectorAll('.message-item-wrapper.messenger').forEach((wrapper, idx) => {
      wrapper.querySelectorAll('img').forEach(img => {
        if (img.classList.contains('emotion')) return;
        if (img.src && img.src.startsWith('http') && !seen.has(img.src)) {
          seen.add(img.src);
          results.push({ url: img.src.substring(0, 120), messageIndex: idx });
        }
      });
    });
    return results;
  });

  if (imageEntries.length > 0) {
    console.log(`\n=== IMAGES (${imageEntries.length}) ===`);
    imageEntries.forEach(img => console.log(`  msg[${img.messageIndex}]: ${img.url}`));
  } else {
    console.log('\n(No images found)');
  }

  // Check for card data
  const cards = messages.filter(m => m.messageType === 'card');
  if (cards.length > 0) {
    console.log(`\n=== CARD MESSAGES (${cards.length}) ===`);
    cards.forEach(c => console.log(`  [${c.index}] ${c.content.substring(0, 100)}`));
  }

  await browser.close();
  console.log('\nDone.');
}

testAmerly().catch(err => {
  console.error('Test failed:', err.message);
  process.exit(1);
});

