// ============================================================
async function generateReport() {
  console.log('📄 生成跟进分析报告...\n');

  const data = loadLatest('数据快照_');
  if (!data.length) {
    console.error('未找到数据快照文件');
    process.exit(1);
  }
  console.log(`   加载 ${data.length} 个客户数据`);

  // 分析所有客户
  const analyzed = data.map(conv => analyzeCustomer(conv))
    .filter(a => a.category !== 'skip');

  // 按优先级排序
  const tierOrder = { P0_S: 0, P0_A: 1, P0_B: 2, P1_A: 3, P1_B: 4, P2_B: 5, P2_C: 6, P3_C: 7 };
  analyzed.sort((a, b) => (tierOrder[a.tier] || 99) - (tierOrder[b.tier] || 99));

  // 统计
  const totalMsg = analyzed.reduce((s, a) => s + a.total, 0);
  const totalImg = analyzed.reduce((s, a) => s + a.images, 0);
  const unreadCount = analyzed.filter(a => a.isUnread).length;
  const p0Count = analyzed.filter(a => a.tier.startsWith('P0')).length;
  const p1Count = analyzed.filter(a => a.tier.startsWith('P1')).length;

  // 分组
  const p0Customers = analyzed.filter(a => a.tier.startsWith('P0'));
  const p1Customers = analyzed.filter(a => a.tier.startsWith('P1'));
  const p2Customers = analyzed.filter(a => a.tier.startsWith('P2'));
  const p3Customers = analyzed.filter(a => a.tier.startsWith('P3'));

  // 构建文档
  const children = [];

  // === 封面 ===
  children.push(new Paragraph({ spacing: { before: 2400 }, children: [] }));
  children.push(new Paragraph({
    children: [new TextRun({ text: '小满CRM 客户跟进分析报告', bold: true, size: 44, color: '1A1A1A' })],
    alignment: AlignmentType.CENTER,
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: 'AI-Powered Customer Follow-up Intelligence', size: 24, color: '888888', italics: true })],
    alignment: AlignmentType.CENTER,
    spacing: { after: 600 },
  }));

  const timestamp = new Date().toISOString().replace('T', ' ').substring(0, 19);
  children.push(new Paragraph({
    children: [new TextRun({ text: `生成时间: ${timestamp}`, size: 20, color: '666666' })],
    alignment: AlignmentType.CENTER,
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: `数据来源: 小满CRM (Okki) 阿里巴巴国际站TM聊天`, size: 18, color: '999999' })],
    alignment: AlignmentType.CENTER,
    spacing: { after: 200 },
  }));

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === 概览 ===
  children.push(sectionHeader('一、数据概览'));

  const overviewStats = [
    ['总客户数', `${analyzed.length} 个`],
    ['总消息数', `${totalMsg} 条`],
    ['总图片数', `${totalImg} 张`],
    ['未读消息', `${unreadCount} 个客户`],
    ['紧急(P0)', `${p0Count} 个客户`],
    ['优先(P1)', `${p1Count} 个客户`],
    ['计划(P2)', `${p2Customers.length} 个客户`],
    ['常规(P3)', `${p3Customers.length} 个客户`],
  ];

  const statsTable = new Table({
    width: { size: 100, type: WidthType.PERCENTAGE },
    rows: [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '指标', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 40, type: WidthType.PERCENTAGE } }),
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '数值', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 60, type: WidthType.PERCENTAGE } }),
        ],
      }),
      ...overviewStats.map(([label, value], i) =>
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 20 })] })], shading: i % 2 === 0 ? { fill: 'F5F5F5' } : undefined }),
            new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: value, size: 20, color: value.includes('0') && label.includes('紧急') ? 'D32F2F' : '333333' })] })], shading: i % 2 === 0 ? { fill: 'F5F5F5' } : undefined }),
          ],
        })
      ),
    ],
  });
  children.push(statsTable);

  children.push(new Paragraph({ spacing: { after: 200 }, children: [] }));

  // 紧急行动清单
  children.push(new Paragraph({
    children: [new TextRun({ text: '⚡ 今天必须处理:', bold: true, size: 22, color: 'C00000' })],
    spacing: { before: 300, after: 100 },
  }));

  const urgentItems = [
    '1. Susuanna ParkerAdentwi — 订单确认中，地址/联系人/价格全确认，只差下单！',
    '2. Krisgel Igros — 运费确认后立刻报总价，客户明确要10件试单',
    '3. amer ly — 今天已跟进(物流方案)，明早确认是否回复',
    '4. Amal Alamhrooqi — DDP物流争议5天未解，需联系客户确认是否接受DAP',
    '5. rehema kiseyu — 样品确认等待中，下午发跟进',
  ];
  for (const item of urgentItems) {
    children.push(new Paragraph({
      children: [new TextRun({ text: item, size: 18, color: '333333' })],
      spacing: { after: 40 },
    }));
  }

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === P0: 紧急 ===
  children.push(sectionHeader('二、紧急处理 (P0)'));
  children.push(new Paragraph({
    children: [new TextRun({ text: '需要今天/24小时内处理的客户。涉及订单确认、价格谈判、售后问题。', size: 19, color: '666666' })],
    spacing: { after: 200 },
  }));
  for (const c of p0Customers) {
    children.push(...customerBlock(c));
  }

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === P1: 优先 ===
  children.push(sectionHeader('三、优先跟进 (P1)'));
  children.push(new Paragraph({
    children: [new TextRun({ text: '48小时内跟进。有明确意向但流程未走完的客户。', size: 19, color: '666666' })],
    spacing: { after: 200 },
  }));
  for (const c of p1Customers) {
    children.push(...customerBlock(c));
  }

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === P2: 计划 ===
  children.push(sectionHeader('四、计划跟进 (P2)'));
  children.push(new Paragraph({
    children: [new TextRun({ text: '1周内跟进。历史有互动但需要回访的客户。', size: 19, color: '666666' })],
    spacing: { after: 200 },
  }));
  for (const c of p2Customers) {
    children.push(...customerBlock(c));
  }

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === P3: 常规 ===
  children.push(sectionHeader('五、常规维护 (P3)'));
  children.push(new Paragraph({
    children: [new TextRun({ text: '低优先级。新线索、个人买家、待激活客户，可批量处理。', size: 19, color: '666666' })],
    spacing: { after: 200 },
  }));
  for (const c of p3Customers) {
    children.push(...customerBlock(c));
  }

  // === 尾页: 行动检查清单 ===
  children.push(new Paragraph({ children: [new PageBreak()] }));
  children.push(sectionHeader('六、行动检查清单'));

  const today = new Date().toISOString().substring(0, 10);
  children.push(new Paragraph({
    children: [new TextRun({ text: `报告日期: ${today}`, size: 18, color: '666666' })],
    spacing: { after: 200 },
  }));

  const todoItems = [
    { check: false, text: 'Susuanna ParkerAdentwi — 创建订单/PI，发给客户确认', priority: 'P0' },
    { check: false, text: 'Krisgel Igros — 确认运费，发送总价报价', priority: 'P0' },
    { check: false, text: 'amer ly — 确认客户是否收到物流方案，是否需要DDP替代', priority: 'P0' },
    { check: false, text: 'Amal Alamhrooqi — 确认DDP物流是否可行，或建议客户自清关', priority: 'P0' },
    { check: false, text: 'rehema kiseyu — 发送样品跟进消息', priority: 'P0' },
    { check: false, text: 'zainab Babesets — 发阿拉伯语跟进，确认12件/设计的需求', priority: 'P1' },
    { check: false, text: 'azaan ss — 换个角度发跟进(不追问价格)', priority: 'P1' },
    { check: false, text: 'Aula Alsaad — 针对新发的产品卡，给阶梯报价', priority: 'P1' },
    { check: false, text: 'fernande Pochette — 第二次跟进(产品实拍/案例)', priority: 'P1' },
    { check: false, text: 'Cindy Nadal — 确认法语报价是否收到', priority: 'P1' },
    { check: false, text: 'Regina Kabanda — 简短跟进', priority: 'P1' },
    { check: false, text: 'Ahmed Darrat — 澄清产品匹配，重新报价', priority: 'P2' },
    { check: false, text: 'Adm Reda — 确认经理答复，报2件价格', priority: 'P2' },
    { check: false, text: 'Sayfullaeva Shahnoza — 简短跟进', priority: 'P2' },
    { check: false, text: 'Maimouna Cisse — 法语跟进', priority: 'P2' },
  ];

  const checkTable = new Table({
    width: { size: 100, type: WidthType.PERCENTAGE },
    rows: [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '✓', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 8, type: WidthType.PERCENTAGE } }),
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '行动项', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 72, type: WidthType.PERCENTAGE } }),
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '优先级', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 20, type: WidthType.PERCENTAGE } }),
        ],
      }),
      ...todoItems.map((item, i) => {
        const isUrgent = item.priority === 'P0';
        return new TableRow({
          children: [
            new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '☐', size: 20 })] })], shading: i % 2 === 0 ? { fill: 'FFF8F8' } : undefined }),
            new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: item.text, size: 18, bold: isUrgent, color: isUrgent ? 'C00000' : '333333' })] })], shading: i % 2 === 0 ? { fill: 'FFF8F8' } : undefined }),
            new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: item.priority, bold: true, size: 18, color: isUrgent ? 'C00000' : '333333' })], alignment: AlignmentType.CENTER })] }),
          ],
        });
      }),
    ],
  });
  children.push(checkTable);

  children.push(new Paragraph({ spacing: { after: 200 }, children: [] }));
  children.push(new Paragraph({
    children: [new TextRun({ text: '报告由 AI (Claude) 基于小满CRM实时数据生成，仅供参考。所有报价和商务决策请与老板确认。', size: 16, color: 'AAAAAA', italics: true })],
    alignment: AlignmentType.CENTER,
  }));

  // 保存
  const doc = new Document({
    title: '小满CRM客户跟进分析报告',
    creator: 'Claude AI + 小星星服饰',
    sections: [{ children }],
  });

  const buffer = await Packer.toBuffer(doc);
  const reportPath = join(DATA_DIR, `客户跟进报告_${timestamp.replace(/:/g, '-').substring(0, 19)}.docx`);
  writeFileSync(reportPath, buffer);

  console.log(`\n✅ 报告已生成: ${reportPath}`);

  // 打印摘要
  console.log(`\n=== 报告摘要 ===`);
  console.log(`总客户: ${analyzed.length} | P0: ${p0Count} | P1: ${p1Count} | P2: ${p2Customers.length} | P3: ${p3Customers.length}`);
  console.log(`\n--- P0 紧急 ---`);
  for (const c of p0Customers) {
    console.log(`  [${c.tier}] ${c.name.padEnd(30)} ${c.label}`);
  }
  console.log(`\n--- P1 优先 ---`);
  for (const c of p1Customers) {
    console.log(`  [${c.tier}] ${c.name.padEnd(30)} ${c.label}`);
  }
  console.log(`\n--- P2 计划 ---`);
  for (const c of p2Customers) {
    console.log(`  [${c.tier}] ${c.name.padEnd(30)} ${c.label}`);
  }
  console.log(`\n--- P3 常规 ---`);
  for (const c of p3Customers) {
    console.log(`  [${c.tier}] ${c.name.padEnd(30)} ${c.label}`);
  }
}

generateReport().catch(err => {
  console.error('❌ 生成失败:', err.message);
  console.error(err.stack);
  process.exit(1);
});

