/**
 * 小满CRM — 客户跟进分析报告生成器
 *
 * 读取抓取数据 → 逐客户分析 → 生成Word报告
 * 用法: node scripts/report-generator.mjs
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, ShadingType, WidthType,
  PageBreak, TableOfContents,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');

// ============================================================
// 加载最新数据
// ============================================================
function loadLatest(pattern) {
  const files = readdirSync(DATA_DIR)
    .filter(f => f.startsWith(pattern) && f.endsWith('.json'))
    .sort().reverse();
  if (!files.length) return [];
  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf-8'));
}

// ============================================================
// 客户分类（基于我分析全部数据后的判断）
// ============================================================
const PRIORITY_COLORS = {
  P0_S: 'C00000', P0_A: 'FF0000', P0_B: 'FF6347',
  P1_A: 'FF8C00', P1_B: 'FFA500',
  P2_B: '4169E1', P2_C: '6A5ACD',
  P3_C: '808080',
};

function analyzeCustomer(conv) {
  const { name, messages = [], images = [], status } = conv;
  const total = messages.length;
  const last = messages[messages.length - 1];
  const first = messages[0];
  const sent = messages.filter(m => m.side === 'sent' && !m.isSystem);
  const received = messages.filter(m => m.side === 'received');
  const allText = messages.map(m => m.content || '').join(' ').toLowerCase();

  const lastTime = messages.filter(m => m.timestamp).pop()?.timestamp || '未知';
  const firstTime = messages.find(m => m.timestamp)?.timestamp || '未知';
  const lastIsReceived = last && last.side === 'received';
  const lastIsSent = last && last.side === 'sent';
  const isUnread = status === 'unread';

  // Find product cards
  const cards = messages.filter(m => m.isCard && m.content);

  const analysis = { name, total, images: images.length, isUnread, lastTime, firstTime };

  // === amer ly: 伊拉克，28件询盘，报价已发，物流已报，等确认 ===
  if (name === 'amer ly') {
    return { ...analysis, category: 'negotiating', label: '谈判中', tier: 'P0_A',
      summary: '伊拉克客户(Hussein)，7色×4尺码共28件Summer Boys Outfit Set。报价$3.8/件($106.4)，DAP运费$157到Nasiriyah。客户发了完整物流地址，询问DDP到Oman。已解释DAP需自行清关并发送报价，等待客户确认。',
      customerProfile: '国家: 伊拉克 | 身份: 零售商/个人 | 语言: 阿拉伯语 | 最后活跃: 4月28日 17:34',
      nextStep: '无需再催——今天刚发完物流方案("يتطلب هذا المخطط اللوجستي...")，等客户24h回复。如明天无回复，发送简短跟进确认是否收到物流方案。',
      talkingPoints: ['强调DAP模式是他自己清关，我们已经给了最优惠运费', '如果客户坚持DDP，可以再问一次货代有没有新线路'],
      risk: '低。客户互动积极(19条消息)，发送了😂表情，关系融洽。唯一风险是DDP到伊拉克线路不通。' };
  }

  // === rehema kiseyu: 坦桑尼亚，样品单，16色×多码 ===
  if (name === 'rehema kiseyu') {
    return { ...analysis, category: 'sample_request', label: '待寄样', tier: 'P0_A',
      summary: '坦桑尼亚客户，询盘两个产品(Sleeveless Sport Set + Boys Clothing Set)，16色×80-120cm各1件，样品测试单。我方已回复样品费可退、5-7天生产，询问地址/包装/图案要求。客户未回复。',
      customerProfile: '国家: 坦桑尼亚 | 身份: 零售商 | 语言: 英语 | 最后活跃: 4月28日 01:17',
      nextStep: '客户最后消息在凌晨1点(北京时间)，今天下午/傍晚发一条友好跟进。话术要点：确认是否还在评估、样品费可退、提供具体下一步。',
      talkingPoints: ['样品费正式订单可退', '5-7天样品生产', '强调Disney代工和16年经验', '问她是否要统一印刷还是不同图案'],
      risk: '中。客户有明确需求(16色×4码)，但可能同时在比价。需要尽快锁定。' };
  }

  // === Susuanna ParkerAdentwi: 未读！订单确认中，已报价未下单 ===
  if (name === 'Susuanna ParkerAdentwi') {
    return { ...analysis, category: 'awaiting_reply', label: '待回复(订单)', tier: 'P0_S',
      summary: '客户已确认产品(Children\'s Pajama Set 10件$46.9含运费$3)、地址(广州白云区)、联系人(LAPAZ)。我方说"After confirmation, I will create an order for you"但之后没有下单。客户也没有回复。状态：未读。',
      customerProfile: '国家: 加纳(推测) | 地址: 广州白云区大朗北路68号 | 联系人: POG-ARABA PARKER | 最后活跃: 4月23日 18:44',
      nextStep: '立即跟进！这个客户已经全部确认好了只差下单。检查草稿订单是否已创建，如未创建，立刻创建并发给客户确认。消息要点：确认订单细节(10件pajama set颜色/尺码)、发送PI链接。',
      talkingPoints: ['订单已准备，确认颜色尺码即可下单', '10件×$4.39+$3运费=$46.9总价', '广州白云区地址已确认'],
      risk: '高！已5天未联系，客户可能在等我们主动下单。这是最接近成交的客户，必须今天处理。' };
  }

  // === Sifa Vano: 未读，个人买家 ===
  if (name === 'Sifa Vano') {
    return { ...analysis, category: 'activate', label: '待激活(个人)', tier: 'P3_C',
      summary: '发了3个产品卡片(Boys Suit/Children Tracksuits/Cotton Worsted Set)，但明确说是"personal"(个人使用)，非商业采购。我方问了具体产品和数量，客户未回复。',
      customerProfile: '语言: 英语 | 身份: 个人买家 | 最后活跃: 4月25日 07:58',
      nextStep: '低优先级。个人买家不是B2B目标客户。可以礼貌回复一次表示"随时欢迎再次咨询"，不投入过多时间。',
      talkingPoints: ['礼貌回复但不投入过多精力'],
      risk: '低。个人买家，不符合工厂MOQ。' };
  }

  // === Regina Kabanda: 未读 ===
  if (name === 'Regina Kabanda') {
    return { ...analysis, category: 'awaiting_reply', label: '待回复', tier: 'P1_B',
      summary: '客户询问2岁宝宝连体衣(Winter Warm Coral Fleece Onesie)，我方确认有6个月-5岁尺码、2岁约90cm。客户未回复最后一条消息。',
      customerProfile: '语言: 英语 | 身份: 个人消费者(推测) | 最后活跃: 4月24日 17:34',
      nextStep: '发送简短跟进，询问是否需要下单、需要几件。如果是个人使用可发2件样品价。',
      talkingPoints: ['2岁约90cm', '可发2-5件小单', '询问送货地址'],
      risk: '低。可能是个人消费者，量很小。' };
  }

  // === fernande Pochette: Mohammed，已报价24件Romper，等了6天=待回访 ===
  if (name === 'fernande Pochette') {
    return { ...analysis, category: 'followup', label: '待回访', tier: 'P1_B',
      summary: 'Mohammed(沙特?)询盘100% Cotton Footed Romper，要24件混款(男女)，到美国运费$70 DDP。我方已发报价$8.2/件总$266.8，并在4月27日发送了跟进消息。客户未回复。',
      customerProfile: '国家: 美国(目的地)/沙特(推测) | 身份: 零售商 | 最后活跃: 4月21日 01:52',
      nextStep: '已过7天，再发第二次跟进。可以发产品实拍图或类似客户案例，强调ROMper质量和Disney代工资质。',
      talkingPoints: ['产品实拍/案例分享', '强调100%棉+环保+舒适', '可提供免费样板'],
      risk: '中。24件建议零售单，但客户已沉默7天，可能在比价或失去兴趣。' };
  }

  // === azaan ss: 反复问价，报了$3.8/$3.85，200件混码 ===
  if (name === 'azaan ss') {
    return { ...analysis, category: 'negotiating', label: '谈判中(价格)', tier: 'P0_B',
      summary: '客户多次问"How much"，对Custom Kids Set 2 Pcs感兴趣，要200件混码。我方报了$3.8-3.85/件，发送了面料信息(棉布)和云盘文件。客户最后问"do you think there\'s something I did wrong, or is it that you don\'t find the price acceptable?"——我方主动追问。客户未回复。',
      customerProfile: '语言: 英语 | 身份: 零售商(推测) | 最后活跃: 4月26日 21:05',
      nextStep: '我方最后一条消息是敏感追问("是我做错了还是价格不接受")。等1-2天，如无回复，换个角度——发产品案例或问是否需要调整配置来适配预算。',
      talkingPoints: ['不直接降价，而是调整配置(面料/数量/包装)', '强调Disney代工资质', '询问具体目标市场'],
      risk: '中。客户反复问价说明有意向，但可能对价格敏感。追问"是我做错了什么"略消极。' };
  }

  // === User name (1): Fathima，价格争端，$3.47 vs $5.60 ===
  if (name === 'User name' && total >= 15) {
    return { ...analysis, category: 'activate', label: '待激活(价格争端)', tier: 'P3_C',
      summary: 'Fathima(印度?)客户，广告显示$3.47但报价$5.60，客户强烈反对("In india its too expensive", "I have no profit")。我方解释这是定制清仓价，正常$5.60。客户说"ok thankyou"后没有再互动。',
      customerProfile: '国家: 印度(推测) | 身份: 零售商 | 最后活跃: 4月27日 20:29',
      nextStep: '放弃。客户明确表示价格不可接受，且市场需求(印度)与工厂定位不匹配。可以发一条消息表示"如果有新产品会推荐"。',
      talkingPoints: ['礼貌结束，不纠缠价格'],
      risk: '低。已基本丢失。' };
  }

  // === Cindy Nadal: 法语客户，DDP $68，已报价，等回复 ===
