// ============================================================
// Word 样式
// ============================================================
const TIER_COLORS = {
  'P0_S': 'C00000', 'P0_A': 'D32F2F', 'P0_B': 'E53935',
  'P1_A': 'E65100', 'P1_B': 'EF6C00',
  'P2_B': '1565C0', 'P2_C': '1976D2',
  'P3_C': '757575',
};

function tierBadge(tier) {
  return new TextRun({ text: ` ${tier} `, bold: true, color: 'FFFFFF', shading: { fill: TIER_COLORS[tier] || '757575' }, size: 18 });
}

function sectionHeader(text) {
  return new Paragraph({
    children: [new TextRun({ text, bold: true, size: 28, color: '1A1A1A' })],
    spacing: { before: 360, after: 200 },
    border: { bottom: { color: TIER_COLORS['P0_A'] || 'D32F2F', size: 6, style: BorderStyle.SINGLE } },
  });
}

function customerBlock(analysis) {
  const children = [];

  // Customer name + tier badge
  children.push(new Paragraph({
    children: [
      new TextRun({ text: analysis.name, bold: true, size: 24, color: '1A1A1A' }),
      tierBadge(analysis.tier),
      new TextRun({ text: `  ${analysis.label}`, color: TIER_COLORS[analysis.tier] || '757575', size: 20 }),
    ],
    spacing: { before: 300, after: 100 },
  }));

  // Profile
  if (analysis.customerProfile) {
    children.push(new Paragraph({
      children: [new TextRun({ text: `📋 ${analysis.customerProfile}`, size: 18, color: '666666', italics: true })],
      spacing: { after: 80 },
    }));
  }

  // Stats
  children.push(new Paragraph({
    children: [new TextRun({ text: `消息: ${analysis.total}条 | 图片: ${analysis.images}张 | ${analysis.isUnread ? '🔴 未读' : '已读'} | ${analysis.firstTime} → ${analysis.lastTime}`, size: 17, color: '888888' })],
    spacing: { after: 100 },
  }));

  // Summary
  children.push(new Paragraph({
    children: [new TextRun({ text: '📋 沟通概要', bold: true, size: 20, color: '333333' })],
    spacing: { after: 40 },
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: analysis.summary, size: 19 })],
    spacing: { after: 100 },
  }));

  // Next step
  children.push(new Paragraph({
    children: [new TextRun({ text: '💡 跟进建议', bold: true, size: 20, color: 'C00000' })],
    spacing: { after: 40 },
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: analysis.nextStep, size: 19, color: '333333' })],
    spacing: { after: 60 },
  }));

  // Talking points
  if (analysis.talkingPoints && analysis.talkingPoints.length > 0) {
    children.push(new Paragraph({
      children: [new TextRun({ text: '话术要点:', bold: true, size: 18, color: '555555' })],
      spacing: { after: 20 },
    }));
    for (const tp of analysis.talkingPoints) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `  • ${tp}`, size: 18, color: '444444' })],
        spacing: { after: 20 },
      }));
    }
  }

  // Risk
  children.push(new Paragraph({
    children: [new TextRun({ text: `⚠️ 风险评估: ${analysis.risk}`, size: 17, color: '888888', italics: true })],
    spacing: { before: 60, after: 60 },
  }));

  // Separator
  children.push(new Paragraph({
    border: { bottom: { color: 'DDDDDD', size: 1, style: BorderStyle.SINGLE } },
    spacing: { after: 80 },
    children: [],
  }));

  return children;
}

