    children: [new TextRun({ text: '小满CRM 客户跟进分析报告', bold: true, size: 44, color: '1A1A1A' })],
    alignment: AlignmentType.CENTER,
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: 'AI-Powered Customer Follow-up Intelligence', size: 24, color: '888888', italics: true })],
    alignment: AlignmentType.CENTER,
    spacing: { after: 600 },
  }));

  const timestamp = new Date().toISOString().replace('T', ' ').substring(0, 19);
  children.push(new Paragraph({
    children: [new TextRun({ text: `生成时间: ${timestamp}`, size: 20, color: '666666' })],
    alignment: AlignmentType.CENTER,
  }));
  children.push(new Paragraph({
    children: [new TextRun({ text: `数据来源: 小满CRM (Okki) 阿里巴巴国际站TM聊天`, size: 18, color: '999999' })],
    alignment: AlignmentType.CENTER,
    spacing: { after: 200 },
  }));

  children.push(new Paragraph({ children: [new PageBreak()] }));

  // === 概览 ===
