    rows: [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ children: [new TextRun({ text: '指标', bold: true, color: 'FFFFFF' })], alignment: AlignmentType.CENTER })], shading: { fill: '333333' }, width: { size: 40, type: WidthType.PERCENTAGE } }),
