  const buffer = await Packer.toBuffer(doc);
  const reportPath = join(DATA_DIR, `客户跟进报告_${timestamp.replace(/:/g, '-').substring(0, 19)}.docx`);
  writeFileSync(reportPath, buffer);

  console.log(`\n✅ 报告已生成: ${reportPath}`);

